10	// TestSharedSocketGatesUnboundDataParity is the T89 acceptance: on a SHARED (multi-view)
11	// concentrator socket, DATA and PARITY arriving from a source with no established
12	// source->peer binding must reach NO peer's resequencer — dropped outright — EVEN when the
13	// frame validly decodes under some peer's codec (a real peer's psk, so the MAC-less
14	// DATA/PARITY body deciphers cleanly under that psk). A DATA/PARITY frame carries no binding
15	// authority (D9/D11: only an authenticated PROBE binds a source), so a garble-decode under
16	// any codec must never attribute the frame to that peer. After an authenticated PROBE binds
17	// the source to peer B, subsequent DATA/PARITY from it route to B's plane only.
18	//
19	// This hardens the T88 multi-peer gate: T88 already `continue`s past a non-PROBE trial-decode
20	// so an unbound DATA/PARITY falls through to the loop-end drop; this test pins that property
21	// down for BOTH kinds and asserts NEITHER peer's resequencer is touched (not merely peer B's).
22	func TestSharedSocketGatesUnboundDataParity(t *testing.T) {
23		pskA := testKey(t, 0x11) // primary
24		pskB := testKey(t, 0x22) // second peer
25	
26		// codecB deciphers exactly as peer B's per-path view codec does (same psk), so a frame it
27		// encodes is guaranteed to VALIDLY decode under peer B's view during the demux trial — the
28		// discriminating case the acceptance calls out ("encode it under a real peer's psk").
29		codecB, err := frame.NewCodec(pskB)
30		if err != nil {
31			t.Fatalf("build peer B codec: %v", err)
32		}
33	
34		t.Run("DATA that validly decodes under peer B's psk from an unbound source reaches no resequencer", func(t *testing.T) {
35			m, primary, second := twoPeerConcentrator(t, pskA, pskB)
36			secondView := peerPathByName(second, "a")
37			_, peerAP := rawPeer(t) // a fresh, unbound source address
38	
39			data, err := codecB.Encode(nil, frame.Data{OuterSeq: 5, PathID: secondView.id, Payload: []byte("unbound-data")})
40			if err != nil {
41				t.Fatalf("encode DATA under psk B: %v", err)
42			}
43			m.demuxInbound(m.paths[0], data, peerAP)
44	
45			// Dropped: neither peer's resequencer received it, and no binding was minted.
46			if it, ok := second.resequencer.Load().Pop(); ok {
47				t.Fatalf("DATA from an UNBOUND source landed in peer B's resequencer (%q); a valid decode must not attribute it", it.Payload)
48			}
49			if it, ok := primary.resequencer.Load().Pop(); ok {
50				t.Fatalf("DATA from an UNBOUND source landed in the PRIMARY resequencer (%q)", it.Payload)
51			}
52			if _, ok := m.lookupPeerBySource(peerAP.Addr()); ok {
53				t.Fatal("an unbound DATA frame established a source->peer binding (D9/D11 violated)")
54			}
55		})
56	
57		t.Run("PARITY that validly decodes under peer B's psk from an unbound source reaches no resequencer", func(t *testing.T) {
58			m, primary, second := twoPeerConcentrator(t, pskA, pskB)
59			secondView := peerPathByName(second, "a")
60			_, peerAP := rawPeer(t)
61	
62			parity, err := codecB.Encode(nil, frame.Parity{FECGroup: 1, ParityIndex: 0, DataCount: 1, PathID: secondView.id, Payload: []byte("unbound-parity")})
63			if err != nil {
64				t.Fatalf("encode PARITY under psk B: %v", err)
65			}
66			m.demuxInbound(m.paths[0], parity, peerAP)
67	
68			if it, ok := second.resequencer.Load().Pop(); ok {
69				t.Fatalf("PARITY from an UNBOUND source landed in peer B's resequencer (%q)", it.Payload)
70			}
71			if it, ok := primary.resequencer.Load().Pop(); ok {
72				t.Fatalf("PARITY from an UNBOUND source landed in the PRIMARY resequencer (%q)", it.Payload)
73			}
74			if _, ok := m.lookupPeerBySource(peerAP.Addr()); ok {
75				t.Fatal("an unbound PARITY frame established a source->peer binding (D9/D11 violated)")
76			}
77		})
78	
79		t.Run("after an authenticated PROBE binds the source to B, subsequent DATA lands in B's resequencer only", func(t *testing.T) {
80			m, primary, second := twoPeerConcentrator(t, pskA, pskB)
81			secondView := peerPathByName(second, "a")
82			peer, peerAP := rawPeer(t)
83	
84			// Pre-binding DATA under B's psk from this source is dropped (the gate above).
85			early, err := codecB.Encode(nil, frame.Data{OuterSeq: 4, PathID: secondView.id, Payload: []byte("early")})
86			if err != nil {
87				t.Fatalf("encode pre-bind DATA: %v", err)
88			}
89			m.demuxInbound(m.paths[0], early, peerAP)
90			if _, ok := m.lookupPeerBySource(peerAP.Addr()); ok {
91				t.Fatal("pre-bind DATA established a binding")
92			}
93	
94			// An authenticated PROBE under peer B's psk binds the source to peer B.
95			const seq = 7
96			ts := newFakeClock().Now().UnixNano()
97			probeRaw, err := frame.Encode(pskB, frame.Probe{PathID: secondView.id, ProbeSeq: seq, TimestampNanos: ts, IsEcho: false})
98			if err != nil {
99				t.Fatalf("encode probe under psk B: %v", err)
100			}
101			m.demuxInbound(m.paths[0], probeRaw, peerAP)
102	
103			bound, ok := m.lookupPeerBySource(peerAP.Addr())
104			if !ok || bound != second {
105				t.Fatalf("PROBE did not bind the source to peer B: bound=%v ok=%v", bound, ok)
106			}
107			// Drain peer B's reflected echo so a later timeout-read in the suite is unambiguous;
108			// its content is asserted by the T88 acceptance, so we only consume it here.
109			echoCodec, _ := frame.NewCodec(pskB)
110			_ = readProbe(t, peer, echoCodec)
111	
112			// Subsequent DATA from the now-bound source lands in peer B's resequencer, and ONLY B's.
113			late, err := codecB.Encode(nil, frame.Data{OuterSeq: 9, PathID: secondView.id, Payload: []byte("late")})
114			if err != nil {
115				t.Fatalf("encode post-bind DATA: %v", err)
116			}
117			m.demuxInbound(m.paths[0], late, peerAP)
118			if it, ok := second.resequencer.Load().Pop(); !ok || !bytes.Equal(it.Payload, []byte("late")) {
119				t.Fatalf("post-bind DATA did not reach peer B's resequencer: ok=%v payload=%q", ok, it.Payload)
120			}
121			if it, ok := primary.resequencer.Load().Pop(); ok {
122				t.Fatalf("post-bind DATA for peer B leaked into the PRIMARY resequencer (%q)", it.Payload)
123			}
124			// The pre-bind "early" frame was never buffered anywhere: peer B's resequencer held
125			// only "late" (already popped) and the primary's held nothing.
126			if it, ok := second.resequencer.Load().Pop(); ok {
127				t.Fatalf("peer B's resequencer held a second frame (%q); the pre-bind DATA was not dropped", it.Payload)
128			}
129		})
130	}
