1	package bind
2	
3	import (
4		"bytes"
5		"crypto/rand"
6		"testing"
7	
8		"github.com/7mind/wanbond/internal/config"
9		"github.com/7mind/wanbond/internal/frame"
10	)
11	
12	// twoPeerConcentrator stands up a Multipath with ONE shared socket ("a") and TWO bound
13	// peers keyed by DISTINCT psks: the primary (pskA) and a second peer (pskB) wired in via
14	// the bindSecondPeer helper (standing in for the concentrator's per-peer wiring). It
15	// returns the bind plus each peer, whose per-(peer,path) view of the shared socket is what
16	// the T88 source->peer demux routes between. m.paths[0] is the primary's view — the value
17	// the Bind-owned readLoop hands demuxInbound for this socket.
18	func twoPeerConcentrator(t *testing.T, pskA, pskB config.Key) (m *Multipath, primary, second *peerState) {
19		t.Helper()
20		clk := newFakeClock()
21		m, _, _ = newProbingMultipath(t, loopbackPaths(1), pskA, clk) // one shared path "a"
22		if _, _, err := m.Open(0); err != nil {
23			t.Fatalf("Open: %v", err)
24		}
25		t.Cleanup(func() { _ = m.Close() })
26		primary = m.peerState
27		second = bindSecondPeer(t, m, "peer-b", pskB, clk)
28		if peerPathByName(second, "a") == nil {
29			t.Fatalf("second peer has no view of shared path 'a': %v", pathNamesOfPeer(second))
30		}
31		return m, primary, second
32	}
33	
34	// TestConcentratorBindsSourceToPeerViaAuthenticatedProbe is the T88 acceptance: with two
35	// peers bound to one shared socket under distinct psks, an inbound PROBE from a fresh
36	// source is trial-decoded against each peer's psk-derived codec and, on the first MAC
37	// that verifies, the source is bound to THAT peer (source->peer) and its probe reflected.
38	// Only an authenticated PROBE binds; a forged frame verifies under no psk and binds
39	// nothing; the trial-decode stops at the first matching psk.
40	func TestConcentratorBindsSourceToPeerViaAuthenticatedProbe(t *testing.T) {
41		pskA := testKey(t, 0x11) // primary
42		pskB := testKey(t, 0x22) // second peer
43	
44		t.Run("authenticated PROBE under peer B's psk binds the source to B and reflects an echo", func(t *testing.T) {
45			m, primary, second := twoPeerConcentrator(t, pskA, pskB)
46			secondView := peerPathByName(second, "a")
47	
48			// A raw loopback socket stands in for peer B's remote uplink: it both is the probe
49			// SOURCE and receives the reflected echo. Its address is a fresh, unbound source.
50			peer, peerAP := rawPeer(t)
51	
52			// A DATA frame from this source BEFORE any PROBE has bound it must be dropped — a
53			// binding is established ONLY by an authenticated PROBE (D9/D11), never by DATA.
54			dataCodecB, _ := frame.NewCodec(pskB)
55			preData, err := dataCodecB.Encode(nil, frame.Data{OuterSeq: 5, PathID: secondView.id, Payload: []byte("early")})
56			if err != nil {
57				t.Fatalf("encode pre-bind DATA: %v", err)
58			}
59			m.demuxInbound(m.paths[0], preData, peerAP)
60			if it, ok := second.resequencer.Load().Pop(); ok {
61				t.Fatalf("DATA from an UNBOUND source was delivered up peer B (%q); only a PROBE may bind first", it.Payload)
62			}
63			if _, ok := m.lookupPeerBySource(peerAP.Addr()); ok {
64				t.Fatal("an unauthenticated DATA frame established a source->peer binding (D9/D11 violated)")
65			}
66	
67			// The authenticated PROBE, encoded under peer B's psk, from the same source.
68			const seq = 7
69			ts := newFakeClock().Now().UnixNano()
70			probeRaw, err := frame.Encode(pskB, frame.Probe{PathID: secondView.id, ProbeSeq: seq, TimestampNanos: ts, IsEcho: false})
71			if err != nil {
72				t.Fatalf("encode probe under psk B: %v", err)
73			}
74			m.demuxInbound(m.paths[0], probeRaw, peerAP)
75	
76			// The source is now bound to peer B (never the primary).
77			bound, ok := m.lookupPeerBySource(peerAP.Addr())
78			if !ok {
79				t.Fatal("authenticated PROBE did not establish a source->peer binding")
80			}
81			if bound != second {
82				t.Fatalf("source bound to the wrong peer: got %q, want peer B", bound.name)
83			}
84	
85			// Peer B learned the probe source as its return remote (authenticated learning, D11);
86			// the primary's view of the socket learned nothing.
87			if remote, ok := secondView.getRemote(); !ok || remote != peerAP {
88				t.Fatalf("peer B view remote = %v (ok=%v), want %v learned from the probe", remote, ok, peerAP)
89			}
90			if _, ok := m.paths[0].getRemote(); ok {
91				t.Fatal("the PRIMARY view learned a remote from a probe that authenticated under peer B's psk")
92			}
93	
94			// The echo landed at the source, encoded under peer B's psk, verbatim ProbeSeq with
95			// IsEcho flipped true — the reflection came from peer B's reflector.
96			echoCodec, _ := frame.NewCodec(pskB)
97			echo := readProbe(t, peer, echoCodec)
98			if !echo.IsEcho || echo.ProbeSeq != seq || echo.PathID != secondView.id {
99				t.Fatalf("reflected echo = %+v, want IsEcho=true seq=%d path=%d under psk B", echo, seq, secondView.id)
100			}
101	
102			// With the source now bound, a subsequent DATA from it is demuxed to peer B's
103			// resequencer (the binding's purpose) — and NOT the primary's.
104			postData, err := dataCodecB.Encode(nil, frame.Data{OuterSeq: 9, PathID: secondView.id, Payload: []byte("late")})
105			if err != nil {
106				t.Fatalf("encode post-bind DATA: %v", err)
107			}
108			m.demuxInbound(m.paths[0], postData, peerAP)
109			if it, ok := second.resequencer.Load().Pop(); !ok || !bytes.Equal(it.Payload, []byte("late")) {
110				t.Fatalf("DATA from the BOUND source was not delivered to peer B: ok=%v payload=%q", ok, it.Payload)
111			}
112			if it, ok := primary.resequencer.Load().Pop(); ok {
113				t.Fatalf("bound peer B's DATA leaked into the PRIMARY resequencer (%q)", it.Payload)
114			}
115		})
116	
117		t.Run("a forged/garbage frame verifies under no peer psk and establishes no binding", func(t *testing.T) {
118			m, primary, second := twoPeerConcentrator(t, pskA, pskB)
119			secondView := peerPathByName(second, "a")
120			peer, peerAP := rawPeer(t)
121	
122			// Random bytes: neither psk's MAC can verify them, so no frame kind is ever recovered.
123			garbage := make([]byte, 128)
124			if _, err := rand.Read(garbage); err != nil {
125				t.Fatalf("draw garbage: %v", err)
126			}
127			m.demuxInbound(m.paths[0], garbage, peerAP)
128	
129			if _, ok := m.lookupPeerBySource(peerAP.Addr()); ok {
130				t.Fatal("a forged/garbage frame established a source->peer binding")
131			}
132			if _, ok := secondView.getRemote(); ok {
133				t.Fatal("a forged frame taught peer B a remote")
134			}
135			if _, ok := m.paths[0].getRemote(); ok {
136				t.Fatal("a forged frame taught the primary a remote")
137			}
138			if it, ok := second.resequencer.Load().Pop(); ok {
139				t.Fatalf("a forged frame was delivered up peer B (%q)", it.Payload)
140			}
141			if it, ok := primary.resequencer.Load().Pop(); ok {
142				t.Fatalf("a forged frame was delivered up the primary (%q)", it.Payload)
143			}
144			// No echo was reflected: a Read with an already-expired deadline returns a timeout
145			// error rather than a datagram.
146			_ = peer.SetReadDeadline(newFakeClock().Now())
147			buf := make([]byte, maxDatagram)
148			if _, _, rerr := peer.ReadFromUDPAddrPort(buf); rerr == nil {
149				t.Fatal("a forged frame was reflected as an echo")
150			}
151		})
152	
153		t.Run("trial-decode STOPS at the first matching psk (discriminating: both peers share a psk)", func(t *testing.T) {
154			// Discriminating design: bind BOTH peers under the SAME psk. A single PROBE then
155			// authenticates under BOTH views' codecs, so the two loop policies diverge observably:
156			//   - stop-at-first-match (correct): only view[0] (the primary) dispatches — exactly ONE
157			//     echo is reflected, the source binds to the primary (the first view), and peer B
158			//     (view[1]) is never consulted, so it learns no remote.
159			//   - a non-stopping loop (the defect this guards against): BOTH views dispatch — TWO
160			//     echoes are reflected and peer B ALSO learns the source as a remote.
161			// Under distinct psks a single PROBE matches only one view, so the two policies would be
162			// indistinguishable; the shared psk is what makes the assertion discriminating.
163			const sharedPsk = 0x33
164			psk := testKey(t, sharedPsk)
165			m, primary, second := twoPeerConcentrator(t, psk, psk)
166			secondView := peerPathByName(second, "a")
167			peer, peerAP := rawPeer(t)
168	
169			const seq = 3
170			ts := newFakeClock().Now().UnixNano()
171			probeRaw, err := frame.Encode(psk, frame.Probe{PathID: m.paths[0].id, ProbeSeq: seq, TimestampNanos: ts, IsEcho: false})
172			if err != nil {
173				t.Fatalf("encode probe under the shared psk: %v", err)
174			}
175			m.demuxInbound(m.paths[0], probeRaw, peerAP)
176	
177			// The source bound to the primary — the FIRST view whose codec yielded a PROBE.
178			bound, ok := m.lookupPeerBySource(peerAP.Addr())
179			if !ok || bound != primary {
180				t.Fatalf("source bound to %v (ok=%v), want the PRIMARY (the first matching psk)", bound, ok)
181			}
182			// Peer B (tried AFTER the primary) was never consulted: no remote learned on its view.
183			// Under a non-stopping loop this getRemote would succeed (B dispatched a second time).
184			if _, ok := secondView.getRemote(); ok {
185				t.Fatal("peer B processed a probe already matched by the primary's psk — the trial-decode did not STOP at the first match")
186			}
187			// EXACTLY ONE echo was reflected (by the primary). Read the first — it must decode under
188			// the shared psk with the verbatim ProbeSeq — then assert a SECOND read finds nothing: a
189			// non-stopping loop would have reflected a second echo from peer B.
190			echoCodec, _ := frame.NewCodec(psk)
191			echo := readProbe(t, peer, echoCodec)
192			if !echo.IsEcho || echo.ProbeSeq != seq {
193				t.Fatalf("reflected echo = %+v, want IsEcho=true seq=%d", echo, seq)
194			}
195			_ = peer.SetReadDeadline(newFakeClock().Now())
196			buf := make([]byte, maxDatagram)
197			if _, _, rerr := peer.ReadFromUDPAddrPort(buf); rerr == nil {
198				t.Fatal("a SECOND echo was reflected — the trial-decode did not STOP after the primary matched (both views dispatched)")
199			}
200		})
201	
202		t.Run("a non-PROBE decode under one psk does not abort the trial of the remaining psks", func(t *testing.T) {
203			// Reviewer criticism (R2 #1): the trial-decode must key its stop on the first PROBE that
204			// AUTHENTICATES, not the first successful DECODE. KindData/KindParity carry no MAC and are
205			// forgeable by design, so a genuine peer-B PROBE can cross-psk-garble into a DATA/PARITY
206			// kind under the PRIMARY's codec (~0.4%). If the loop aborted on that non-PROBE decode
207			// (the pre-fix `return`) it would drop peer B's genuine, MAC-verifying PROBE without ever
208			// trying peer B's psk. The loop must instead `continue` past a non-PROBE decode.
209			//
210			// Construct exactly that collision deterministically: encode a genuine PROBE under peer
211			// B's psk, redrawing its random nonce until the SAME bytes decode under the PRIMARY's psk
212			// as a valid non-PROBE kind (DATA/PARITY). Feeding it to demuxInbound must still bind and
213			// dispatch to peer B — proving view[0]'s non-PROBE decode did not abort the trial.
214			m, primary, second := twoPeerConcentrator(t, pskA, pskB)
215			secondView := peerPathByName(second, "a")
216			peer, peerAP := rawPeer(t)
217	
218			const seq = 13
219			ts := newFakeClock().Now().UnixNano()
220			primaryCodec, err := frame.NewCodec(pskA) // decodes identically to the primary's view codec (same psk)
221			if err != nil {
222				t.Fatalf("build primary codec: %v", err)
223			}
224			var probeRaw []byte
225			// The primary decodes a foreign PROBE as a non-PROBE with probability ~2/256 (kind lands
226			// on DATA or PARITY); this budget is ~800x the mean and effectively never exhausts.
227			const searchBudget = 100_000
228			for i := 0; i < searchBudget; i++ {
229				raw, encErr := frame.Encode(pskB, frame.Probe{PathID: secondView.id, ProbeSeq: seq, TimestampNanos: ts, IsEcho: false})
230				if encErr != nil {
231					t.Fatalf("encode probe under psk B: %v", encErr)
232				}
233				fr, decErr := primaryCodec.Decode(raw)
234				if decErr != nil {
235					continue // failed under the primary's psk (ErrAuth/ErrMalformed): not the collision we need
236				}
237				if _, isProbe := fr.(frame.Probe); isProbe {
238					continue // a foreign PROBE can never MAC-verify as a PROBE under psk A; guard anyway
239				}
240				probeRaw = raw // decodes as DATA/PARITY under psk A, yet is a genuine PROBE under psk B
241				break
242			}
243			if probeRaw == nil {
244				t.Fatalf("could not construct a cross-garbling PROBE within %d attempts", searchBudget)
245			}
246	
247			m.demuxInbound(m.paths[0], probeRaw, peerAP)
248	
249			// Peer B's PROBE authenticated on the SECOND trial (after the primary's non-PROBE decode
250			// did NOT abort the loop): the source bound to peer B.
251			bound, ok := m.lookupPeerBySource(peerAP.Addr())
252			if !ok {
253				t.Fatal("a genuine peer-B PROBE that decoded as a non-PROBE under the primary's psk was dropped — the trial-decode aborted at the first successful DECODE instead of the first MAC")
254			}
255			if bound != second {
256				t.Fatalf("source bound to the wrong peer: got %q, want peer B", bound.name)
257			}
258			// Peer B learned the source as its remote and reflected the echo under psk B.
259			if remote, ok := secondView.getRemote(); !ok || remote != peerAP {
260				t.Fatalf("peer B view remote = %v (ok=%v), want %v learned from the probe", remote, ok, peerAP)
261			}
262			echoCodec, _ := frame.NewCodec(pskB)
263			echo := readProbe(t, peer, echoCodec)
264			if !echo.IsEcho || echo.ProbeSeq != seq || echo.PathID != secondView.id {
265				t.Fatalf("reflected echo = %+v, want IsEcho=true seq=%d path=%d under psk B", echo, seq, secondView.id)
266			}
267			// The primary's non-PROBE decode was NOT dispatched: its resequencer stays empty and it
268			// learned no remote (a non-PROBE carries no binding authority and is dropped).
269			if _, ok := m.paths[0].getRemote(); ok {
270				t.Fatal("the primary learned a remote from a frame that only cross-garbled into a non-PROBE kind under its psk")
271			}
272			if it, ok := primary.resequencer.Load().Pop(); ok {
273				t.Fatalf("a non-PROBE cross-garble was delivered up the primary (%q)", it.Payload)
274			}
275		})
276	}
