type Config struct {
	// DataShards is N, the maximum number of DATA frames grouped before parity is
	// emitted. Must be >= 1.
	DataShards int
	// ParityShards is K, the number of parity frames emitted per group and the
	// maximum number of per-group losses the receiver can recover. Must be >= 1.
	ParityShards int
	// Deadline bounds the grouping latency: an open, partially-filled group is
	// flushed (parity emitted over its current data frames) once this much time
	// has elapsed since its first frame. Must be > 0.
	Deadline time.Duration
}

// Validate reports whether the configuration is a usable Reed-Solomon FEC ratio,
// failing fast on an out-of-range shard count or a non-positive deadline. It is the
// exported form of the same invariant NewEncoder/NewDecoder enforce, so a caller (the
// multipath Bind, T24) can reject a bad ratio before constructing either.
func (c Config) Validate() error { return c.validate() }

func (c Config) validate() error {
	if c.DataShards < 1 {
		return fmt.Errorf("fec: DataShards must be >= 1, got %d", c.DataShards)
	}
	if c.ParityShards < 1 {
		return fmt.Errorf("fec: ParityShards must be >= 1, got %d", c.ParityShards)
	}
	if c.DataShards+c.ParityShards > maxShards {
		return fmt.Errorf("fec: DataShards+ParityShards must be <= %d, got %d", maxShards, c.DataShards+c.ParityShards)
	}
	if c.Deadline <= 0 {
		return fmt.Errorf("fec: Deadline must be > 0, got %s", c.Deadline)
	}
	return nil

type DecoderStats struct {
	// Recovered is the number of data shards reconstructed from parity.
	Recovered uint64
	// Unrecoverable is the number of data shards lost beyond repair capacity — the
	// per-group missing count of a group evicted from the retain window before it
	// could be completed (its M was known from a parity frame but < M shards
	// survived). A group whose parity was ALSO entirely lost (M never learned) is
	// not counted here: with no surviving parity the decoder has no information
	// about the group's cardinality, and the loss is accounted downstream by the
	// resequencer's gap timeout instead.
	Unrecoverable uint64
}

// Stats returns a snapshot of the decoder's cumulative recovery counters. Before
// snapshotting it folds in every retained-incomplete group whose recovery deadline
// has definitively passed (accountExpired, D24), so at quiescence — when no new
// group is offered to advance the eviction high-water — a doomed tail group is
// counted unrecoverable promptly rather than only once ~retainWindow later groups
// arrive. Each group is counted exactly once (accountExpired marks it accounted, and
// the later window eviction skips an already-accounted group). This makes Stats a
// read-with-side-effects; the datapath serializes it with Offer under the receiver's
// mutex, matching the decoder's single-writer discipline.
func (d *Decoder) Stats() DecoderStats {
	d.accountExpired()
	return DecoderStats{Recovered: d.recovered, Unrecoverable: d.unrecoverable}
}

// accountEviction folds a group being dropped from the retain window into the
// unrecoverable counter: a group whose cardinality M is known (a parity frame was
// seen) but is not yet done was lost for good — fewer than M of its M+K shards

